export const meta = {
  name: 'sprint-v2-tests-docs',
  description: 'Parallel test rewrite + documentation update for sprint-ledger v2',
  phases: [
    { title: 'Tests', detail: '3 agents with disjoint test-file ownership' },
    { title: 'Docs', detail: '3 agents with disjoint doc-file ownership' },
  ],
}

const ROOT = '/Users/doruk/Desktop/SIDE_HUSTLE/decree'
const DESIGN = '/private/tmp/claude-501/-Users-doruk-Desktop-SIDE-HUSTLE-decree/9aba7607-c379-42b0-82e5-f238fc1a47cb/scratchpad/sprint-v2-design.md'
const FACTS = '/private/tmp/claude-501/-Users-doruk-Desktop-SIDE-HUSTLE-decree/9aba7607-c379-42b0-82e5-f238fc1a47cb/scratchpad/impl-facts.md'

const RESULT_SCHEMA = {
  type: 'object',
  required: ['summary', 'files_changed', 'verification'],
  properties: {
    summary: { type: 'string' },
    files_changed: {
      type: 'array',
      items: {
        type: 'object',
        required: ['path', 'detail'],
